document.addEventListener('DOMContentLoaded', () => {

    // ============================================================
    // FORMATTERS & HELPERS
    // ============================================================
    const fmtMoney = (n) => {
        if (n >= 1e6) return '$' + (n / 1e6).toFixed(1) + 'M';
        if (n >= 1e3) return '$' + (n / 1e3).toFixed(0) + 'K';
        return '$' + Math.round(n);
    };
    const fmtNum = (n) => n.toLocaleString('en-US', { maximumFractionDigits: 0 });
    const fmtDate = (ts) => new Date(ts * 1000).toLocaleDateString('en-US', { day: 'numeric', month: 'short', year: 'numeric' });
    const fmtDateShort = (ts) => new Date(ts * 1000).toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
    const fmtDateISO = (iso) => new Date(iso).toLocaleDateString('en-US', { day: 'numeric', month: 'short', year: 'numeric' });
    const debounce = (fn, ms) => { let t; return (...a) => { clearTimeout(t); t = setTimeout(() => fn(...a), ms); }; };
    const escapeHtml = (s) => String(s || '').replace(/[&<>"']/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));

    // ============================================================
    // TABS
    // ============================================================
    const switchTab = (target) => {
        document.querySelectorAll('.tab').forEach(t => t.classList.toggle('active', t.dataset.tab === target));
        document.querySelectorAll('.tab-panel').forEach(p => p.classList.toggle('active', p.id === target));
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    document.querySelectorAll('[data-tab]').forEach(btn => {
        btn.addEventListener('click', () => switchTab(btn.dataset.tab));
    });

    document.querySelectorAll('[data-tab-link]').forEach(a => {
        a.addEventListener('click', (e) => {
            e.preventDefault();
            switchTab(a.dataset.tabLink);
            document.getElementById('navMobile')?.classList.remove('open');
        });
    });

    // ============================================================
    // NAV & UI
    // ============================================================
    const navToggle = document.getElementById('navToggle');
    const navMobile = document.getElementById('navMobile');
    navToggle?.addEventListener('click', () => {
        const open = navMobile.classList.toggle('open');
        navToggle.setAttribute('aria-expanded', open);
    });

    const btt = document.getElementById('backToTop');
    window.addEventListener('scroll', () => {
        if (window.scrollY > 600) { btt.hidden = false; btt.classList.add('show'); }
        else { btt.classList.remove('show'); setTimeout(() => btt.hidden = true, 200); }
    }, { passive: true });
    btt.addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));

    // ============================================================
    // FREELANCER METRICS
    // ============================================================
    const flReviews = FREELANCER_DATA.reviews || [];
    const flTotal = flReviews.length;

    const flMetrics = (() => {
        if (!flTotal) return null;

        const totalRevenue = flReviews.reduce((s, r) => s + (r.price_usd || 0), 0);
        const ratedReviews = flReviews.filter(r => r.rating > 0);
        const avgRating = ratedReviews.length ? ratedReviews.reduce((s, r) => s + r.rating, 0) / ratedReviews.length : 0;
        const uniqueClients = new Set(flReviews.map(r => r.from_user_id)).size;
        const completeCount = flReviews.filter(r => r.review_project_status === 'complete').length;
        const fiveStar = flReviews.filter(r => r.rating >= 4.95).length;
        const negCount = flReviews.filter(r => r.rating > 0 && r.rating <= 2.0).length;

        const clientMap = {};
        flReviews.forEach(r => {
            const cid = r.from_user_id;
            if (!clientMap[cid]) clientMap[cid] = { id: cid, reviews: [], totalUsd: 0, ratings: [] };
            clientMap[cid].reviews.push(r);
            clientMap[cid].totalUsd += r.price_usd || 0;
            if (r.rating > 0) clientMap[cid].ratings.push(r.rating);
        });
        const repeatClients = Object.values(clientMap).filter(c => c.reviews.length >= 2).sort((a, b) => b.totalUsd - a.totalUsd);

        let onTimeYes = 0, onTimeNo = 0, onBudgetYes = 0, onBudgetNo = 0;
        flReviews.forEach(r => {
            const d = r.rating_details; if (!d) return;
            const ot = d.on_time_display, ob = d.on_budget_display;
            if (ot === 'YES' || ot === '100%') onTimeYes++; else if (ot === 'NO') onTimeNo++;
            if (ob === 'YES' || ob === '100%') onBudgetYes++; else if (ob === 'NO') onBudgetNo++;
        });

        const dates = flReviews.map(r => r.time_submitted).sort();
        const earliest = new Date(dates[0] * 1000);
        const latest = new Date(dates[dates.length - 1] * 1000);

        return {
            totalRevenue, avgRating, uniqueClients, completeCount, fiveStar, negCount,
            clientMap, repeatClients, onTimeYes, onTimeNo, onBudgetYes, onBudgetNo, earliest, latest
        };
    })();

    // ============================================================
    // GLASSDOOR METRICS
    // ============================================================
    const gdReviews = GLASSDOOR_DATA.reviews || [];
    const gdSummary = GLASSDOOR_DATA.summary || {};
    const gdRatings = gdSummary.ratings || {};

    const gdMetrics = (() => {
        if (!gdReviews.length) return null;

        const ratedReviews = gdReviews.filter(r => r.ratingOverall > 0);
        const avgOverall = gdRatings.overallRating || (ratedReviews.reduce((s, r) => s + r.ratingOverall, 0) / Math.max(ratedReviews.length, 1));

        const recommends = gdReviews.filter(r => r.recommendToFriend === 'POSITIVE').length;
        const wontRec = gdReviews.filter(r => r.recommendToFriend === 'NEGATIVE').length;
        const ceoApprove = gdReviews.filter(r => r.ceoApproval === 'APPROVE').length;
        const ceoDisapprove = gdReviews.filter(r => r.ceoApproval === 'DISAPPROVE').length;
        const ceoNeutral = gdReviews.filter(r => r.ceoApproval === 'NO_OPINION').length;
        const outlookPos = gdReviews.filter(r => r.businessOutlook === 'POSITIVE').length;
        const outlookNeg = gdReviews.filter(r => r.businessOutlook === 'NEGATIVE').length;
        const outlookNeu = gdReviews.filter(r => r.businessOutlook === 'NEUTRAL').length;

        return { avgOverall, recommends, wontRec, ceoApprove, ceoDisapprove, ceoNeutral, outlookPos, outlookNeg, outlookNeu };
    })();

    // ============================================================
    // OVERVIEW TAB
    // ============================================================
    if (flMetrics) {
        document.getElementById('ovFreelancer').innerHTML = `
      <div class="ov-stat"><div class="ov-num">${flTotal}</div><div class="ov-lbl">Reviews</div></div>
      <div class="ov-stat"><div class="ov-num">${flMetrics.avgRating.toFixed(2)}</div><div class="ov-lbl">Avg Rating</div></div>
      <div class="ov-stat"><div class="ov-num">${fmtMoney(flMetrics.totalRevenue)}</div><div class="ov-lbl">Total Revenue</div></div>
      <div class="ov-stat"><div class="ov-num">${flMetrics.uniqueClients}</div><div class="ov-lbl">Unique Clients</div></div>`;
    }

    if (gdMetrics) {
        const recRate = (gdMetrics.recommends + gdMetrics.wontRec) > 0
            ? Math.round(gdMetrics.recommends / (gdMetrics.recommends + gdMetrics.wontRec) * 100) : 0;
        document.getElementById('ovGlassdoor').innerHTML = `
      <div class="ov-stat"><div class="ov-num">${gdReviews.length}</div><div class="ov-lbl">Reviews</div></div>
      <div class="ov-stat"><div class="ov-num">${gdMetrics.avgOverall.toFixed(1)}</div><div class="ov-lbl">Overall Rating</div></div>
      <div class="ov-stat"><div class="ov-num">${recRate}%</div><div class="ov-lbl">Recommend</div></div>
      <div class="ov-stat"><div class="ov-num">${gdRatings.workLifeBalanceRating?.toFixed(1) || '—'}</div><div class="ov-lbl">Work-Life</div></div>`;
    }

    document.getElementById('ovPlaystore').innerHTML = `
    <div class="ov-stat"><div class="ov-num">${PLAYSTORE_DATA.accounts.length}</div><div class="ov-lbl">Publisher Accounts</div></div>
    <div class="ov-stat"><div class="ov-num">3</div><div class="ov-lbl">Product Lines</div></div>
    <div class="ov-stat"><div class="ov-num">LLP</div><div class="ov-lbl">India</div></div>
    <div class="ov-stat"><div class="ov-num">LLC</div><div class="ov-lbl">US</div></div>`;

    // Cross-source insight
    const ovInsight = document.getElementById('ovInsight');
    if (flMetrics && gdMetrics) {
        const flAvg = flMetrics.avgRating.toFixed(2);
        const gdAvg = gdMetrics.avgOverall.toFixed(1);
        const gap = (parseFloat(flAvg) - parseFloat(gdAvg)).toFixed(1);
        ovInsight.innerHTML = `
      <strong>Cross-source pattern:</strong> Clients rate Vasundhara <strong>${flAvg}/5</strong> on Freelancer.com, while employees rate the company <strong>${gdAvg}/5</strong> on Glassdoor — a gap of <strong>${gap} points</strong>.
      This is common for service agencies where client satisfaction (delivery quality) outpaces internal employee experience (work culture, compensation).
      Worth examining the cons section in Glassdoor for actionable culture signals.`;
    }

    // ============================================================
    // FREELANCER TAB
    // ============================================================
    if (flMetrics) {
        const cards = [
            { num: flTotal, lbl: 'Total Reviews', sub: `${flMetrics.earliest.getFullYear()} – ${flMetrics.latest.getFullYear()}`, type: 'int' },
            { num: flMetrics.totalRevenue, lbl: 'Total Revenue', sub: 'All currencies → USD', type: 'money' },
            { num: flMetrics.avgRating, lbl: 'Avg Rating', sub: `${flMetrics.fiveStar} five-star`, cls: 'good', type: 'decimal' },
            { num: flMetrics.uniqueClients, lbl: 'Unique Clients', sub: `${flMetrics.repeatClients.length} repeat (2+)`, type: 'int' },
            { num: flMetrics.completeCount, lbl: 'Completed', sub: `${flTotal - flMetrics.completeCount} incomplete`, type: 'int' },
            { num: flMetrics.negCount, lbl: 'Negative (≤2.0)', sub: `${(flMetrics.negCount / flTotal * 100).toFixed(1)}% of total`, cls: 'warn', type: 'int' },
            {
                num: flMetrics.onTimeYes + flMetrics.onTimeNo > 0 ? Math.round(flMetrics.onTimeYes / (flMetrics.onTimeYes + flMetrics.onTimeNo) * 100) : 0,
                lbl: 'On Time', sub: `${flMetrics.onTimeYes} yes / ${flMetrics.onTimeNo} no`, cls: 'good', type: 'percent'
            },
            {
                num: flMetrics.onBudgetYes + flMetrics.onBudgetNo > 0 ? Math.round(flMetrics.onBudgetYes / (flMetrics.onBudgetYes + flMetrics.onBudgetNo) * 100) : 0,
                lbl: 'On Budget', sub: `${flMetrics.onBudgetYes} yes / ${flMetrics.onBudgetNo} no`, cls: 'good', type: 'percent'
            },
        ];

        const formatCard = (val, type) => {
            if (type === 'money') return fmtMoney(val);
            if (type === 'decimal') return val.toFixed(2);
            if (type === 'percent') return val + '%';
            return fmtNum(val);
        };

        document.getElementById('summaryCards').innerHTML = cards.map((c, i) =>
            `<div class="s-card ${c.cls || ''}" style="animation-delay:${i * 50}ms">
        <div class="num" data-target="${c.num}" data-type="${c.type}">${formatCard(0, c.type)}</div>
        <div class="lbl">${c.lbl}</div>
        ${c.sub ? `<div class="sub">${c.sub}</div>` : ''}
      </div>`
        ).join('');

        // Count-up animation
        const animateCount = (el) => {
            const target = parseFloat(el.dataset.target);
            const type = el.dataset.type;
            const duration = 1200;
            const start = performance.now();
            const step = (now) => {
                const p = Math.min((now - start) / duration, 1);
                const eased = 1 - Math.pow(1 - p, 3);
                el.textContent = formatCard(target * eased, type);
                if (p < 1) requestAnimationFrame(step);
                else el.textContent = formatCard(target, type);
            };
            requestAnimationFrame(step);
        };
        const countObs = new IntersectionObserver((entries) => {
            entries.forEach(e => { if (e.isIntersecting) { animateCount(e.target); countObs.unobserve(e.target); } });
        }, { threshold: 0.5 });
        document.querySelectorAll('.s-card .num').forEach(el => countObs.observe(el));
    }

    // ============================================================
    // FREELANCER CHARTS
    // ============================================================
    const flCharts = {};
    const PALETTE = ['#CC785C', '#E8B4A0', '#5C7A4F', '#B85C3E', '#C9A24C', '#6B6B66',
        '#3D3D3A', '#8B6F5F', '#7A9B6B', '#D4A24C', '#9B7A5C', '#5C6B7A'];

    const renderFreelancerCharts = () => {
        if (typeof Chart === 'undefined' || !flMetrics) { setTimeout(renderFreelancerCharts, 100); return; }

        Chart.defaults.color = '#6B6B66';
        Chart.defaults.borderColor = '#E5E2D6';
        Chart.defaults.font.family = "'Inter', sans-serif";

        const baseOpts = {
            responsive: true, maintainAspectRatio: false,
            plugins: { legend: { display: false } },
            animation: { duration: 800, easing: 'easeOutQuart' }
        };

        // Rating distribution
        const ratingBuckets = { '5.0': 0, '4.0–4.9': 0, '3.0–3.9': 0, '2.0–2.9': 0, '1.0–1.9': 0, '0 (Dispute)': 0 };
        flReviews.forEach(r => {
            if (r.rating >= 4.95) ratingBuckets['5.0']++;
            else if (r.rating >= 4.0) ratingBuckets['4.0–4.9']++;
            else if (r.rating >= 3.0) ratingBuckets['3.0–3.9']++;
            else if (r.rating >= 2.0) ratingBuckets['2.0–2.9']++;
            else if (r.rating >= 0.1) ratingBuckets['1.0–1.9']++;
            else ratingBuckets['0 (Dispute)']++;
        });
        flCharts.rating = new Chart(document.getElementById('chartRating'), {
            type: 'bar',
            data: { labels: Object.keys(ratingBuckets), datasets: [{ data: Object.values(ratingBuckets), backgroundColor: ['#5C7A4F', '#8B9B6B', '#C9A24C', '#E8B4A0', '#CC785C', '#B85C3E'], borderRadius: 6 }] },
            options: { ...baseOpts, scales: { y: { beginAtZero: true, grid: { color: '#E5E2D6' } }, x: { grid: { display: false } } } }
        });

        // Revenue by year
        const yearRev = {};
        flReviews.forEach(r => {
            const y = new Date(r.time_submitted * 1000).getFullYear();
            yearRev[y] = (yearRev[y] || 0) + (r.price_usd || 0);
        });
        const yearKeys = Object.keys(yearRev).sort();
        flCharts.revenue = new Chart(document.getElementById('chartRevenue'), {
            type: 'bar',
            data: { labels: yearKeys, datasets: [{ data: yearKeys.map(y => Math.round(yearRev[y])), backgroundColor: '#CC785C', borderRadius: 6 }] },
            options: { ...baseOpts, scales: { y: { beginAtZero: true, grid: { color: '#E5E2D6' }, ticks: { callback: v => fmtMoney(v) } }, x: { grid: { display: false } } } }
        });

        // Categories
        const catMap = {};
        flReviews.forEach(r => {
            const url = r.review_context?.seo_url || '';
            const parts = url.split('/');
            const cat = parts.length >= 2 ? parts[1] : 'other';
            catMap[cat] = (catMap[cat] || 0) + 1;
        });
        const catSorted = Object.entries(catMap).sort((a, b) => b[1] - a[1]).slice(0, 12);
        flCharts.categories = new Chart(document.getElementById('chartCategories'), {
            type: 'doughnut',
            data: { labels: catSorted.map(c => c[0]), datasets: [{ data: catSorted.map(c => c[1]), backgroundColor: PALETTE, borderWidth: 2, borderColor: '#FAF9F5' }] },
            options: { responsive: true, maintainAspectRatio: false, cutout: '60%', plugins: { legend: { position: 'right', labels: { font: { size: 11 }, padding: 8, boxWidth: 10 } } } }
        });

        // Delivery
        flCharts.delivery = new Chart(document.getElementById('chartDelivery'), {
            type: 'bar',
            data: {
                labels: ['On Time', 'Late', 'On Budget', 'Over Budget'],
                datasets: [{ data: [flMetrics.onTimeYes, flMetrics.onTimeNo, flMetrics.onBudgetYes, flMetrics.onBudgetNo], backgroundColor: ['#5C7A4F', '#B85C3E', '#5C7A4F', '#B85C3E'], borderRadius: 6 }]
            },
            options: { ...baseOpts, scales: { y: { beginAtZero: true, grid: { color: '#E5E2D6' } }, x: { grid: { display: false } } } }
        });

        // Category ratings
        const catRatingSums = { professionalism: 0, communication: 0, quality: 0, expertise: 0, hire_again: 0 };
        const catRatingCounts = { ...catRatingSums };
        flReviews.forEach(r => {
            const cr = r.rating_details?.category_ratings; if (!cr) return;
            Object.keys(catRatingSums).forEach(k => {
                if (cr[k] != null) { catRatingSums[k] += cr[k]; catRatingCounts[k]++; }
            });
        });
        const catRatingAvgs = Object.keys(catRatingSums).map(k => catRatingCounts[k] ? +(catRatingSums[k] / catRatingCounts[k]).toFixed(2) : 0);
        flCharts.catRatings = new Chart(document.getElementById('chartCatRatings'), {
            type: 'radar',
            data: {
                labels: ['Professionalism', 'Communication', 'Quality', 'Expertise', 'Hire Again'],
                datasets: [{ data: catRatingAvgs, backgroundColor: 'rgba(204, 120, 92, 0.15)', borderColor: '#CC785C', pointBackgroundColor: '#CC785C', borderWidth: 2, pointRadius: 4 }]
            },
            options: { responsive: true, maintainAspectRatio: false, scales: { r: { min: 0, max: 5, ticks: { stepSize: 1, color: '#6B6B66', backdropColor: 'transparent' }, grid: { color: '#E5E2D6' }, angleLines: { color: '#E5E2D6' }, pointLabels: { color: '#1F1E1D', font: { size: 11 } } } }, plugins: { legend: { display: false } } }
        });

        // Currency
        const currMap = {};
        flReviews.forEach(r => { const cc = r.currency?.code || 'USD'; currMap[cc] = (currMap[cc] || 0) + 1; });
        const currSorted = Object.entries(currMap).sort((a, b) => b[1] - a[1]);
        flCharts.currency = new Chart(document.getElementById('chartCurrency'), {
            type: 'doughnut',
            data: { labels: currSorted.map(c => c[0]), datasets: [{ data: currSorted.map(c => c[1]), backgroundColor: PALETTE, borderWidth: 2, borderColor: '#FAF9F5' }] },
            options: { responsive: true, maintainAspectRatio: false, cutout: '60%', plugins: { legend: { position: 'right', labels: { font: { size: 11 }, padding: 8, boxWidth: 10 } } } }
        });
    };

    // Lazy render
    const flChartObs = new IntersectionObserver((entries, obs) => {
        if (entries[0].isIntersecting) { renderFreelancerCharts(); obs.disconnect(); }
    }, { rootMargin: '200px' });
    const flChartTarget = document.getElementById('chartRating');
    if (flChartTarget) flChartObs.observe(flChartTarget);

    // ============================================================
    // FREELANCER CLIENT TABLE
    // ============================================================
    if (flMetrics) {
        let clientSortKey = 'spend', clientSortDir = -1;

        const renderClients = () => {
            const sorted = [...flMetrics.repeatClients].sort((a, b) => {
                if (clientSortKey === 'name') return clientSortDir * (a.id - b.id);
                if (clientSortKey === 'count') return clientSortDir * (a.reviews.length - b.reviews.length);
                if (clientSortKey === 'spend') return clientSortDir * (a.totalUsd - b.totalUsd);
                if (clientSortKey === 'avg') {
                    const aa = a.ratings.length ? a.ratings.reduce((s, v) => s + v, 0) / a.ratings.length : 0;
                    const bb = b.ratings.length ? b.ratings.reduce((s, v) => s + v, 0) / b.ratings.length : 0;
                    return clientSortDir * (aa - bb);
                }
                if (clientSortKey === 'first') return clientSortDir * (Math.min(...a.reviews.map(r => r.time_submitted)) - Math.min(...b.reviews.map(r => r.time_submitted)));
                if (clientSortKey === 'last') return clientSortDir * (Math.max(...a.reviews.map(r => r.time_submitted)) - Math.max(...b.reviews.map(r => r.time_submitted)));
                return 0;
            });

            document.getElementById('clientBody').innerHTML = sorted.map(c => {
                const avg = c.ratings.length ? (c.ratings.reduce((s, v) => s + v, 0) / c.ratings.length).toFixed(2) : '—';
                const first = Math.min(...c.reviews.map(r => r.time_submitted));
                const last = Math.max(...c.reviews.map(r => r.time_submitted));
                const projects = c.reviews.map(r => r.review_context?.context_name || '').filter(Boolean).slice(0, 3).join(', ');
                const avgColor = parseFloat(avg) >= 4.5 ? 'var(--good)' : parseFloat(avg) >= 3 ? 'var(--gold)' : 'var(--warn)';
                return `<tr>
          <td><div class="tbl-name">#${c.id}</div><div class="tbl-sub">${escapeHtml(projects.substring(0, 60))}${projects.length > 60 ? '…' : ''}</div></td>
          <td><strong>${c.reviews.length}</strong></td>
          <td><strong>$${fmtNum(c.totalUsd)}</strong></td>
          <td><span style="color:${avgColor};font-weight:600">${avg}</span></td>
          <td>${fmtDateShort(first)}</td>
          <td>${fmtDateShort(last)}</td>
        </tr>`;
            }).join('');

            document.querySelectorAll('#clientTable th').forEach(t => {
                const icon = t.querySelector('.sort-icon');
                if (t.dataset.sort === clientSortKey) {
                    t.classList.add('active');
                    if (icon) icon.textContent = clientSortDir === -1 ? '↓' : '↑';
                } else {
                    t.classList.remove('active');
                    if (icon) icon.textContent = '↕';
                }
            });
        };

        document.querySelectorAll('#clientTable th').forEach(th => {
            th.addEventListener('click', () => {
                const key = th.dataset.sort;
                if (clientSortKey === key) clientSortDir *= -1;
                else { clientSortKey = key; clientSortDir = -1; }
                renderClients();
            });
        });

        renderClients();

        // CSV Export
        document.getElementById('exportCSV')?.addEventListener('click', () => {
            const rows = [['Client ID', 'Projects', 'Total Spend USD', 'Avg Rating', 'First Review', 'Last Review']];
            flMetrics.repeatClients.forEach(c => {
                const avg = c.ratings.length ? (c.ratings.reduce((s, v) => s + v, 0) / c.ratings.length).toFixed(2) : '';
                const first = fmtDate(Math.min(...c.reviews.map(r => r.time_submitted)));
                const last = fmtDate(Math.max(...c.reviews.map(r => r.time_submitted)));
                rows.push([c.id, c.reviews.length, c.totalUsd.toFixed(2), avg, first, last]);
            });
            const csv = rows.map(r => r.map(v => `"${String(v).replace(/"/g, '""')}"`).join(',')).join('\n');
            const blob = new Blob([csv], { type: 'text/csv' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url; a.download = 'vasundhara-clients.csv'; a.click();
            URL.revokeObjectURL(url);
        });
    }

    // ============================================================
    // FREELANCER INSIGHTS
    // ============================================================
    if (flMetrics) {
        const biggestProjects = [...flReviews].sort((a, b) => (b.price_usd || 0) - (a.price_usd || 0)).slice(0, 5);
        const negReviews = flReviews.filter(r => r.rating > 0 && r.rating <= 2.0).sort((a, b) => a.rating - b.rating);

        const bids = flReviews.filter(r => r.bid_amount > 0 && r.paid_amount > 0);
        const avgBid = bids.length ? bids.reduce((s, r) => s + r.bid_amount, 0) / bids.length : 0;
        const avgPaid = bids.length ? bids.reduce((s, r) => s + r.paid_amount, 0) / bids.length : 0;
        const sortedPaid = flReviews.map(r => r.price_usd || 0).filter(v => v > 0).sort((a, b) => a - b);
        const medianPaid = sortedPaid[Math.floor(sortedPaid.length / 2)] || 0;

        document.getElementById('insightGrid').innerHTML = `
      <div class="insight">
        <h4><i class="fa-solid fa-trophy"></i> Biggest Projects (USD)</h4>
        ${biggestProjects.map(r => `<div class="insight-row"><span class="insight-key">${escapeHtml((r.review_context?.context_name || '').substring(0, 40))}</span><span class="insight-val">$${fmtNum(r.price_usd || 0)}</span></div>`).join('')}
      </div>
      <div class="insight">
        <h4><i class="fa-solid fa-triangle-exclamation"></i> Negative Reviews (≤2.0)</h4>
        ${negReviews.length === 0 ? '<div class="insight-row"><span class="insight-key">None found 🎉</span></div>' :
                negReviews.slice(0, 6).map(r => `<div class="insight-row"><span class="insight-key">${escapeHtml((r.review_context?.context_name || '').substring(0, 35))}</span><span class="insight-val" style="color:var(--warn)">${r.rating.toFixed(1)} ★</span></div>`).join('')}
      </div>
      <div class="insight">
        <h4><i class="fa-solid fa-coins"></i> Bid vs Paid</h4>
        <div class="insight-row"><span class="insight-key">Avg Bid</span><span class="insight-val">$${avgBid.toFixed(0)}</span></div>
        <div class="insight-row"><span class="insight-key">Avg Paid</span><span class="insight-val">$${avgPaid.toFixed(0)}</span></div>
        <div class="insight-row"><span class="insight-key">Multiplier</span><span class="insight-val">${avgBid ? (avgPaid / avgBid).toFixed(1) : '—'}x</span></div>
        <div class="insight-row"><span class="insight-key">Median Paid</span><span class="insight-val">$${medianPaid.toFixed(0)}</span></div>
      </div>
      <div class="insight">
        <h4><i class="fa-solid fa-users"></i> Client Retention</h4>
        <div class="insight-row"><span class="insight-key">1-time clients</span><span class="insight-val">${Object.values(flMetrics.clientMap).filter(c => c.reviews.length === 1).length}</span></div>
        <div class="insight-row"><span class="insight-key">2-time clients</span><span class="insight-val">${Object.values(flMetrics.clientMap).filter(c => c.reviews.length === 2).length}</span></div>
        <div class="insight-row"><span class="insight-key">3-5 projects</span><span class="insight-val">${Object.values(flMetrics.clientMap).filter(c => c.reviews.length >= 3 && c.reviews.length <= 5).length}</span></div>
        <div class="insight-row"><span class="insight-key">6+ projects</span><span class="insight-val">${Object.values(flMetrics.clientMap).filter(c => c.reviews.length >= 6).length}</span></div>
      </div>
      <div class="insight">
        <h4><i class="fa-solid fa-handshake"></i> Longest Relationships</h4>
        ${Object.values(flMetrics.clientMap).filter(c => c.reviews.length >= 2).map(c => {
                    const ts = c.reviews.map(r => r.time_submitted);
                    return { id: c.id, span: (Math.max(...ts) - Math.min(...ts)) / (86400 * 365), count: c.reviews.length };
                }).sort((a, b) => b.span - a.span).slice(0, 5).map(c =>
                    `<div class="insight-row"><span class="insight-key">#${c.id} (${c.count} proj)</span><span class="insight-val">${c.span.toFixed(1)} years</span></div>`
                ).join('')}
      </div>
      <div class="insight">
        <h4><i class="fa-solid fa-chart-line"></i> Activity Span</h4>
        <div class="insight-row"><span class="insight-key">First review</span><span class="insight-val">${flMetrics.earliest.toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}</span></div>
        <div class="insight-row"><span class="insight-key">Latest review</span><span class="insight-val">${flMetrics.latest.toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}</span></div>
        <div class="insight-row"><span class="insight-key">Total years</span><span class="insight-val">${((flMetrics.latest - flMetrics.earliest) / (1000 * 86400 * 365)).toFixed(1)}</span></div>
        <div class="insight-row"><span class="insight-key">Reviews/year</span><span class="insight-val">${(flTotal / Math.max(((flMetrics.latest - flMetrics.earliest) / (1000 * 86400 * 365)), 1)).toFixed(1)}</span></div>
      </div>`;
    }

    // ============================================================
    // FREELANCER REVIEWS — search/filter/paginate
    // ============================================================
    if (flMetrics) {
        const PER_PAGE = 12;
        let filtered = [...flReviews];
        let page = 0;

        const applyFilters = () => {
            const q = document.getElementById('rvSearch').value.toLowerCase().trim();
            const ratingFilter = document.getElementById('rvRating').value;
            const statusFilter = document.getElementById('rvStatus').value;
            const sortVal = document.getElementById('rvSort').value;

            document.getElementById('searchClear').hidden = q === '';

            filtered = flReviews.filter(r => {
                if (q && !(r.review_context?.context_name || '').toLowerCase().includes(q) && !(r.description || '').toLowerCase().includes(q)) return false;
                if (statusFilter !== 'all' && r.review_project_status !== statusFilter) return false;
                if (ratingFilter !== 'all') {
                    const rf = parseInt(ratingFilter);
                    if (rf === 5 && r.rating < 4.95) return false;
                    if (rf === 4 && (r.rating < 4.0 || r.rating >= 4.95)) return false;
                    if (rf === 3 && (r.rating < 3.0 || r.rating >= 4.0)) return false;
                    if (rf === 2 && (r.rating < 2.0 || r.rating >= 3.0)) return false;
                    if (rf === 1 && r.rating >= 2.0) return false;
                }
                return true;
            });

            const sorters = {
                'date-desc': (a, b) => b.time_submitted - a.time_submitted,
                'date-asc': (a, b) => a.time_submitted - b.time_submitted,
                'rating-desc': (a, b) => b.rating - a.rating,
                'rating-asc': (a, b) => a.rating - b.rating,
                'amount-desc': (a, b) => (b.price_usd || 0) - (a.price_usd || 0),
                'amount-asc': (a, b) => (a.price_usd || 0) - (b.price_usd || 0)
            };
            if (sorters[sortVal]) filtered.sort(sorters[sortVal]);

            page = 0;
            renderFlReviews();
        };

        const renderFlReviews = () => {
            const start = page * PER_PAGE;
            const slice = filtered.slice(start, start + PER_PAGE);
            const totalPages = Math.max(1, Math.ceil(filtered.length / PER_PAGE));

            document.getElementById('rvMeta').textContent =
                filtered.length === 0 ? '0 reviews' : `${filtered.length} reviews · Page ${page + 1} of ${totalPages}`;

            if (filtered.length === 0) {
                document.getElementById('rvList').innerHTML = `
          <div class="rv-empty">
            <i class="fa-solid fa-magnifying-glass"></i>
            <h4>No reviews match your filters</h4>
            <p>Try adjusting your search or clearing filters.</p>
          </div>`;
                document.getElementById('rvPagination').innerHTML = '';
                return;
            }

            document.getElementById('rvList').innerHTML = slice.map(r => {
                const name = escapeHtml(r.review_context?.context_name || 'Unnamed Project');
                const fullDesc = (r.description || '').split('\n')[0];
                const desc = escapeHtml(fullDesc.substring(0, 240));
                const rClass = r.rating >= 4.0 ? 'pos' : r.rating <= 2.5 && r.rating > 0 ? 'neg' : '';
                const rColor = r.rating >= 4.5 ? 'high' : r.rating <= 2.5 && r.rating > 0 ? 'low' : '';
                const onTime = r.rating_details?.on_time_display || '—';
                const onBudget = r.rating_details?.on_budget_display || '—';
                const otClass = (onTime === 'YES' || onTime === '100%') ? 'good' : onTime === 'NO' ? 'warn' : '';
                const obClass = (onBudget === 'YES' || onBudget === '100%') ? 'good' : onBudget === 'NO' ? 'warn' : '';
                const paidAmt = r.paid_amount || 0;

                return `<div class="rv ${rClass}">
          <div class="rv-head">
            <div class="rv-proj">${name}</div>
            <div class="rv-rating ${rColor}">${r.rating > 0 ? r.rating.toFixed(1) : '⚠'}</div>
          </div>
          <div class="rv-meta">
            <span class="tag"><i class="fa-solid fa-calendar"></i>${fmtDate(r.time_submitted)}</span>
            ${paidAmt > 0 ? `<span class="tag"><i class="fa-solid fa-dollar-sign"></i>${r.currency?.sign || '$'}${fmtNum(paidAmt)} ${r.currency?.code || 'USD'}</span>` : ''}
            ${r.price_usd > 0 && r.currency?.code !== 'USD' ? `<span class="tag"><i class="fa-solid fa-right-left"></i>$${fmtNum(r.price_usd)} USD</span>` : ''}
            <span class="tag ${otClass}"><i class="fa-solid fa-clock"></i>On-time: ${onTime}</span>
            <span class="tag ${obClass}"><i class="fa-solid fa-wallet"></i>On-budget: ${onBudget}</span>
            <span class="tag"><i class="fa-solid fa-${r.review_project_status === 'complete' ? 'check' : 'xmark'}"></i>${r.review_project_status}</span>
            ${r.featured ? '<span class="tag gold"><i class="fa-solid fa-star"></i>Featured</span>' : ''}
          </div>
          <div class="rv-text">${desc}${fullDesc.length > 240 ? '…' : ''}</div>
          <div class="rv-foot">
            <span>Client #${r.from_user_id} · Project #${r.project_id}</span>
          </div>
        </div>`;
            }).join('');

            document.querySelectorAll('.rv').forEach(el => {
                el.addEventListener('click', () => el.querySelector('.rv-text')?.classList.toggle('expanded'));
            });

            // Pagination
            const pag = document.getElementById('rvPagination');
            if (totalPages <= 1) { pag.innerHTML = ''; return; }
            let btns = `<button ${page === 0 ? 'disabled' : ''} data-go="${page - 1}">← Prev</button>`;
            const maxBtns = 7;
            let startP = Math.max(0, page - Math.floor(maxBtns / 2));
            let endP = Math.min(totalPages, startP + maxBtns);
            if (endP - startP < maxBtns) startP = Math.max(0, endP - maxBtns);
            for (let i = startP; i < endP; i++) {
                btns += `<button class="${i === page ? 'active' : ''}" data-go="${i}">${i + 1}</button>`;
            }
            btns += `<button ${page === totalPages - 1 ? 'disabled' : ''} data-go="${page + 1}">Next →</button>`;
            pag.innerHTML = btns;
            pag.querySelectorAll('button[data-go]').forEach(b => {
                b.addEventListener('click', () => { page = parseInt(b.dataset.go); renderFlReviews(); });
            });
        };

        document.getElementById('searchClear')?.addEventListener('click', () => {
            const inp = document.getElementById('rvSearch'); inp.value = ''; inp.focus(); applyFilters();
        });
        document.getElementById('rvSearch')?.addEventListener('input', debounce(applyFilters, 200));
        document.getElementById('rvRating')?.addEventListener('change', applyFilters);
        document.getElementById('rvStatus')?.addEventListener('change', applyFilters);
        document.getElementById('rvSort')?.addEventListener('change', applyFilters);

        document.addEventListener('keydown', (e) => {
            if (e.key === '/' && document.activeElement.tagName !== 'INPUT' && document.querySelector('#freelancer.active')) {
                e.preventDefault();
                document.getElementById('rvSearch')?.focus();
            }
        });

        applyFilters();
    }

    // ============================================================
    // GLASSDOOR — RATING HERO
    // ============================================================
    if (gdMetrics) {
        document.getElementById('gdCeoName').textContent = gdRatings.ratedCeo?.name || 'Somish Kakadiya';

        const stars = (val, max = 5) => {
            const filled = Math.round(val);
            return '★'.repeat(filled) + '<span class="empty">' + '★'.repeat(max - filled) + '</span>';
        };

        const pillars = [
            { key: 'workLifeBalanceRating', lbl: 'Work-Life Balance' },
            { key: 'compensationAndBenefitsRating', lbl: 'Compensation & Benefits' },
            { key: 'cultureAndValuesRating', lbl: 'Culture & Values' },
            { key: 'careerOpportunitiesRating', lbl: 'Career Opportunities' },
            { key: 'seniorManagementRating', lbl: 'Senior Management' },
            { key: 'diversityAndInclusionRating', lbl: 'Diversity & Inclusion' }
        ];

        document.getElementById('gdRatingHero').innerHTML = `
      <div class="gd-overall">
        <div class="gd-overall-num">${gdMetrics.avgOverall.toFixed(1)}</div>
        <div class="gd-overall-stars">${stars(gdMetrics.avgOverall)}</div>
        <div class="gd-overall-lbl">Overall Rating</div>
        <div class="gd-overall-count">Based on ${gdReviews.length} reviews</div>
      </div>
      <div class="gd-pillar-grid">
        ${pillars.map(p => {
            const val = gdRatings[p.key] || 0;
            const pct = (val / 5) * 100;
            return `<div class="gd-pillar">
            <div class="gd-pillar-head">
              <span class="gd-pillar-lbl">${p.lbl}</span>
              <span class="gd-pillar-val">${val.toFixed(1)}</span>
            </div>
            <div class="gd-pillar-bar"><div class="gd-pillar-fill" style="width:0%" data-target="${pct}"></div></div>
          </div>`;
        }).join('')}
      </div>`;

        // Animate pillar bars on scroll
        const pillarObs = new IntersectionObserver((entries) => {
            entries.forEach(e => {
                if (e.isIntersecting) {
                    e.target.querySelectorAll('.gd-pillar-fill').forEach(f => {
                        setTimeout(() => f.style.width = f.dataset.target + '%', 100);
                    });
                    pillarObs.unobserve(e.target);
                }
            });
        }, { threshold: 0.3 });
        pillarObs.observe(document.getElementById('gdRatingHero'));
    }

    // ============================================================
    // GLASSDOOR CHARTS
    // ============================================================
    const gdCharts = {};

    const renderGlassdoorCharts = () => {
        if (typeof Chart === 'undefined' || !gdMetrics) { setTimeout(renderGlassdoorCharts, 100); return; }

        const baseOpts = {
            responsive: true, maintainAspectRatio: false,
            plugins: { legend: { display: false } },
            animation: { duration: 800, easing: 'easeOutQuart' }
        };

        // Sub-ratings radar
        const subData = [
            gdRatings.workLifeBalanceRating,
            gdRatings.compensationAndBenefitsRating,
            gdRatings.cultureAndValuesRating,
            gdRatings.careerOpportunitiesRating,
            gdRatings.seniorManagementRating,
            gdRatings.diversityAndInclusionRating
        ].map(v => +(v || 0).toFixed(2));

        gdCharts.sub = new Chart(document.getElementById('gdSubRatings'), {
            type: 'radar',
            data: {
                labels: ['Work-Life', 'Compensation', 'Culture', 'Career', 'Sr. Mgmt', 'D&I'],
                datasets: [{ data: subData, backgroundColor: 'rgba(204, 120, 92, 0.15)', borderColor: '#CC785C', pointBackgroundColor: '#CC785C', borderWidth: 2, pointRadius: 4 }]
            },
            options: { responsive: true, maintainAspectRatio: false, scales: { r: { min: 0, max: 5, ticks: { stepSize: 1, color: '#6B6B66', backdropColor: 'transparent' }, grid: { color: '#E5E2D6' }, angleLines: { color: '#E5E2D6' }, pointLabels: { color: '#1F1E1D', font: { size: 11 } } } }, plugins: { legend: { display: false } } }
        });

        // Overall rating distribution
        const dist = gdSummary.ratingDistribution?.overall || { _1: 0, _2: 0, _3: 0, _4: 0, _5: 0 };
        gdCharts.overall = new Chart(document.getElementById('gdOverallDist'), {
            type: 'bar',
            data: {
                labels: ['1 ★', '2 ★', '3 ★', '4 ★', '5 ★'],
                datasets: [{ data: [dist._1, dist._2, dist._3, dist._4, dist._5], backgroundColor: ['#B85C3E', '#CC785C', '#C9A24C', '#8B9B6B', '#5C7A4F'], borderRadius: 6 }]
            },
            options: { ...baseOpts, scales: { y: { beginAtZero: true, grid: { color: '#E5E2D6' } }, x: { grid: { display: false } } } }
        });

        // Recommend
        gdCharts.recommend = new Chart(document.getElementById('gdRecommend'), {
            type: 'doughnut',
            data: {
                labels: ['Recommends', "Won't recommend"],
                datasets: [{ data: [gdMetrics.recommends, gdMetrics.wontRec], backgroundColor: ['#5C7A4F', '#B85C3E'], borderWidth: 2, borderColor: '#FAF9F5' }]
            },
            options: { responsive: true, maintainAspectRatio: false, cutout: '65%', plugins: { legend: { position: 'bottom', labels: { font: { size: 12 }, padding: 12, boxWidth: 12 } } } }
        });

        // CEO + Outlook combined
        gdCharts.ceo = new Chart(document.getElementById('gdCeoOutlook'), {
            type: 'bar',
            data: {
                labels: ['CEO Approval', 'Business Outlook'],
                datasets: [
                    { label: 'Positive', data: [gdMetrics.ceoApprove, gdMetrics.outlookPos], backgroundColor: '#5C7A4F', borderRadius: 4 },
                    { label: 'Neutral', data: [gdMetrics.ceoNeutral, gdMetrics.outlookNeu], backgroundColor: '#C9A24C', borderRadius: 4 },
                    { label: 'Negative', data: [gdMetrics.ceoDisapprove, gdMetrics.outlookNeg], backgroundColor: '#B85C3E', borderRadius: 4 }
                ]
            },
            options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { font: { size: 11 }, padding: 8, boxWidth: 10 } } }, scales: { x: { stacked: true, grid: { display: false } }, y: { stacked: true, beginAtZero: true, grid: { color: '#E5E2D6' } } } }
        });

        // Timeline
        const yearMap = {};
        gdReviews.forEach(r => {
            const y = new Date(r.date).getFullYear();
            if (!yearMap[y]) yearMap[y] = { count: 0, sum: 0 };
            yearMap[y].count++;
            yearMap[y].sum += r.ratingOverall;
        });
        const years = Object.keys(yearMap).sort();
        gdCharts.timeline = new Chart(document.getElementById('gdTimeline'), {
            type: 'line',
            data: {
                labels: years,
                datasets: [
                    { type: 'bar', label: 'Reviews', data: years.map(y => yearMap[y].count), backgroundColor: 'rgba(204, 120, 92, 0.6)', borderRadius: 4, yAxisID: 'y' },
                    { type: 'line', label: 'Avg Rating', data: years.map(y => +(yearMap[y].sum / yearMap[y].count).toFixed(2)), borderColor: '#5C7A4F', backgroundColor: '#5C7A4F', tension: 0.35, pointRadius: 4, pointBackgroundColor: '#5C7A4F', yAxisID: 'y1' }
                ]
            },
            options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { font: { size: 11 }, padding: 8, boxWidth: 10 } } }, scales: { y: { beginAtZero: true, grid: { color: '#E5E2D6' }, position: 'left' }, y1: { beginAtZero: true, max: 5, grid: { display: false }, position: 'right' }, x: { grid: { display: false } } } }
        });

        // Roles
        const roleMap = {};
        gdReviews.forEach(r => {
            const role = r.jobTitle || 'Unspecified';
            if (!roleMap[role]) roleMap[role] = { count: 0, sum: 0 };
            roleMap[role].count++;
            roleMap[role].sum += r.ratingOverall;
        });
        const topRoles = Object.entries(roleMap).sort((a, b) => b[1].count - a[1].count).slice(0, 8);
        gdCharts.roles = new Chart(document.getElementById('gdRoles'), {
            type: 'bar',
            data: {
                labels: topRoles.map(r => r[0].length > 24 ? r[0].substring(0, 22) + '…' : r[0]),
                datasets: [{ data: topRoles.map(r => r[1].count), backgroundColor: '#CC785C', borderRadius: 4 }]
            },
            options: { ...baseOpts, indexAxis: 'y', scales: { x: { beginAtZero: true, grid: { color: '#E5E2D6' } }, y: { grid: { display: false } } } }
        });
    };

    const gdChartObs = new IntersectionObserver((entries, obs) => {
        if (entries[0].isIntersecting) { renderGlassdoorCharts(); obs.disconnect(); }
    }, { rootMargin: '200px' });
    const gdChartTarget = document.getElementById('gdSubRatings');
    if (gdChartTarget) gdChartObs.observe(gdChartTarget);

    // ============================================================
    // GLASSDOOR — PROS/CONS WORD FREQUENCY
    // ============================================================
    if (gdMetrics) {
        const STOPWORDS = new Set(['the', 'a', 'an', 'is', 'are', 'was', 'were', 'be', 'been', 'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would', 'should', 'could', 'may', 'might', 'must', 'shall', 'can', 'i', 'you', 'he', 'she', 'it', 'we', 'they', 'me', 'him', 'her', 'us', 'them', 'my', 'your', 'his', 'its', 'our', 'their', 'this', 'that', 'these', 'those', 'and', 'or', 'but', 'if', 'because', 'as', 'until', 'while', 'of', 'at', 'by', 'for', 'with', 'about', 'between', 'into', 'through', 'during', 'before', 'after', 'above', 'below', 'to', 'from', 'up', 'down', 'in', 'out', 'on', 'off', 'over', 'under', 'again', 'further', 'then', 'once', 'here', 'there', 'when', 'where', 'why', 'how', 'all', 'any', 'both', 'each', 'few', 'more', 'most', 'other', 'some', 'such', 'no', 'nor', 'not', 'only', 'own', 'same', 'so', 'than', 'too', 'very', 's', 't', 'just', 'don', 'now', 'na', 'company', 'work', 'lot', 'cons', 'pros', 'also', 'get', 'good', 'great', 'much', 'really', 'one', 'two', 'three', 'will']);

        const extractWords = (text) => {
            return (text || '').toLowerCase()
                .replace(/[^a-z\s]/g, ' ')
                .split(/\s+/)
                .filter(w => w.length >= 4 && !STOPWORDS.has(w));
        };

        const buildWordMap = (key) => {
            const map = {};
            gdReviews.forEach(r => {
                extractWords(r[key]).forEach(w => { map[w] = (map[w] || 0) + 1; });
            });
            return Object.entries(map).filter(([_, c]) => c >= 2).sort((a, b) => b[1] - a[1]).slice(0, 20);
        };

        const renderWordCloud = (id, words) => {
            if (!words.length) {
                document.getElementById(id).innerHTML = '<div style="color:var(--muted);font-size:13px">Not enough data to extract patterns.</div>';
                return;
            }
            const max = words[0][1];
            document.getElementById(id).innerHTML = '<div class="word-cloud">' + words.map(([w, c]) => {
                const size = c >= max * 0.7 ? 'lg' : c >= max * 0.4 ? 'md' : '';
                return `<span class="word ${size}">${escapeHtml(w)}<span class="word-count">${c}</span></span>`;
            }).join('') + '</div>';
        };

        renderWordCloud('gdPros', buildWordMap('pros'));
        renderWordCloud('gdCons', buildWordMap('cons'));
    }

    // ============================================================
    // GLASSDOOR — REVIEWS LIST
    // ============================================================
    if (gdMetrics) {
        let gdFiltered = [...gdReviews];

        const renderStars = (val) => {
            const filled = Math.round(val);
            return '★'.repeat(filled) + '<span class="empty">' + '★'.repeat(5 - filled) + '</span>';
        };

        const applyGdFilters = () => {
            const q = document.getElementById('gdSearch').value.toLowerCase().trim();
            const rf = document.getElementById('gdRatingFilter').value;
            const recF = document.getElementById('gdRecFilter').value;
            const sort = document.getElementById('gdSort').value;

            gdFiltered = gdReviews.filter(r => {
                if (q) {
                    const blob = ((r.summary || '') + ' ' + (r.pros || '') + ' ' + (r.cons || '') + ' ' + (r.jobTitle || '')).toLowerCase();
                    if (!blob.includes(q)) return false;
                }
                if (rf !== 'all' && r.ratingOverall !== parseInt(rf)) return false;
                if (recF !== 'all' && r.recommendToFriend !== recF) return false;
                return true;
            });

            const sorters = {
                'date-desc': (a, b) => new Date(b.date) - new Date(a.date),
                'date-asc': (a, b) => new Date(a.date) - new Date(b.date),
                'rating-desc': (a, b) => b.ratingOverall - a.ratingOverall,
                'rating-asc': (a, b) => a.ratingOverall - b.ratingOverall
            };
            if (sorters[sort]) gdFiltered.sort(sorters[sort]);

            renderGdReviews();
        };

        const renderGdReviews = () => {
            document.getElementById('gdMeta').textContent = `${gdFiltered.length} reviews`;

            if (gdFiltered.length === 0) {
                document.getElementById('gdReviewList').innerHTML = `
          <div class="rv-empty" style="grid-column:1/-1">
            <i class="fa-solid fa-magnifying-glass"></i>
            <h4>No reviews match your filters</h4>
            <p>Try adjusting your search or clearing filters.</p>
          </div>`;
                return;
            }

            document.getElementById('gdReviewList').innerHTML = gdFiltered.map(r => {
                const cls = r.ratingOverall >= 4 ? 'high' : r.ratingOverall <= 2 ? 'low' : '';
                const empStatus = (r.employmentStatus || '').replace('_', ' ').toLowerCase();
                const tenure = r.lengthOfEmployment > 0 ? `${r.lengthOfEmployment}y tenure` : (r.lengthOfEmployment === 0 ? '<1y tenure' : '');
                return `<div class="gd-rv ${cls}">
          <div class="gd-rv-head">
            <div class="gd-rv-title">${escapeHtml(r.summary || 'No title')}</div>
            <div class="gd-rv-stars">${renderStars(r.ratingOverall)}</div>
          </div>
          <div class="gd-rv-meta">
            ${r.jobTitle ? `<span class="tag"><i class="fa-solid fa-briefcase"></i>${escapeHtml(r.jobTitle)}</span>` : ''}
            ${r.location ? `<span class="tag"><i class="fa-solid fa-location-dot"></i>${escapeHtml(r.location)}</span>` : ''}
            <span class="tag"><i class="fa-solid fa-calendar"></i>${fmtDateISO(r.date)}</span>
            ${empStatus ? `<span class="tag">${empStatus}</span>` : ''}
            ${tenure ? `<span class="tag">${tenure}</span>` : ''}
            ${r.isCurrentJob ? '<span class="tag good">Current</span>' : '<span class="tag">Former</span>'}
          </div>
          ${r.pros ? `<div class="gd-rv-section pros"><span class="lbl">Pros</span>${escapeHtml(r.pros)}</div>` : ''}
          ${r.cons ? `<div class="gd-rv-section cons"><span class="lbl">Cons</span>${escapeHtml(r.cons)}</div>` : ''}
          ${r.advice ? `<div class="gd-rv-section advice"><span class="lbl">Advice to Mgmt</span>${escapeHtml(r.advice)}</div>` : ''}
          <div class="gd-rv-foot">
            ${r.recommendToFriend === 'POSITIVE' ? '<span class="tag good"><i class="fa-solid fa-thumbs-up"></i>Recommends</span>' : ''}
            ${r.recommendToFriend === 'NEGATIVE' ? '<span class="tag warn"><i class="fa-solid fa-thumbs-down"></i>Won\'t recommend</span>' : ''}
            ${r.ceoApproval === 'APPROVE' ? '<span class="tag good">Approves CEO</span>' : ''}
            ${r.ceoApproval === 'DISAPPROVE' ? '<span class="tag warn">Disapproves CEO</span>' : ''}
            ${r.businessOutlook === 'POSITIVE' ? '<span class="tag good">Positive outlook</span>' : ''}
            ${r.businessOutlook === 'NEGATIVE' ? '<span class="tag warn">Negative outlook</span>' : ''}
          </div>
        </div>`;
            }).join('');
        };

        document.getElementById('gdSearch')?.addEventListener('input', debounce(applyGdFilters, 200));
        document.getElementById('gdRatingFilter')?.addEventListener('change', applyGdFilters);
        document.getElementById('gdRecFilter')?.addEventListener('change', applyGdFilters);
        document.getElementById('gdSort')?.addEventListener('change', applyGdFilters);

        applyGdFilters();
    }

    // ============================================================
    // PLAY STORE
    // ============================================================
    document.getElementById('psGrid').innerHTML = PLAYSTORE_DATA.accounts.map((a, i) => `
    <div class="ps-card" style="animation-delay:${i * 80}ms">
      <div class="ps-icon"><i class="fa-solid ${a.icon}"></i></div>
      <div class="ps-name">${escapeHtml(a.name)}</div>
      <div class="ps-desc">${escapeHtml(a.desc)}</div>
      <a href="${a.url}" target="_blank" rel="noopener noreferrer" class="ps-btn">
        <i class="fa-brands fa-google-play"></i> Visit on Play Store
      </a>
    </div>
  `).join('');

});